#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        int *evens = (int*)malloc(N * sizeof(int));
        int *odds  = (int*)malloc(N * sizeof(int));
        int ec=0, oc=0;
        for(int i=0;i<N;i++){
            int x; scanf("%d", &x);
            if(x%2==0) evens[ec++] = x; else odds[oc++] = x;
        }
        for(int i=0;i<ec;i++){
            if(i) printf(" ");
            printf("%d", evens[i]);
        }
        for(int i=0;i<oc;i++){
            if(ec||i) printf(" ");
            printf("%d", odds[i]);
        }
        printf("\n");
        free(evens); free(odds);
    }
    return 0;
}

