    while(T--){
        int N; cin>>N;
        vector<int> evens, odds;
        evens.reserve(N); odds.reserve(N);
        for(int i=0;i<N;i++){
            int x; cin>>x;
            if(x%2==0) evens.push_back(x);
            else odds.push_back(x);
        }
        bool first=true;
        for(int v: evens){ if(!first) cout<<' '; cout<<v; first=false; }
        for(int v: odds){ if(!first) cout<<' '; cout<<v; first=false; }
        cout<<'\n';
    }
    return 0;
}

code.Java:
import java.io.*;
import java.util.*;
public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st = new StringTokenizer(br.readLine());
        int T = Integer.parseInt(st.nextToken());
        StringBuilder out = new StringBuilder();
        while (T-- > 0) {
            int N = Integer.parseInt(br.readLine().trim());
            st = new StringTokenizer(br.readLine());
            int[] evens = new int[N];
            int[] odds = new int[N];
            int ec = 0, oc = 0;
            for (int i = 0; i < N; i++) {
                int x = Integer.parseInt(st.nextToken());
                if ((x & 1) == 0) evens[ec++] = x; else odds[oc++] = x;
            }
            for (int i = 0; i < ec; i++) {
                out.append(evens[i]).append(' ');
            }
            for (int i = 0; i < oc; i++) {
                out.append(odds[i]);
                if (i != oc - 1) out.append(' ');
            }
            out.append('\n');
        }
        System.out.print(out.toString());
    }
}

