import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        evens = []
        odds = []
        for _ in range(N):
            x = int(next(it))
            if x % 2 == 0:
                evens.append(str(x))
            else:
                odds.append(str(x))
        out_lines.append(' '.join(evens + odds))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

